import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { HttpClient } from '@angular/common/http';

@Component({
  selector: 'app-titling-tracker',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './titling-tracker.component.html',
  styleUrls: ['./titling-tracker.component.css']
})
export class TitlingTrackerComponent implements OnInit {
  requests: any[] = [];
  selectedRequest: any = null;
  logs: any[] = [];
  isLoading: boolean = true;

  steps = [
    { key: 'DOSSIER_SUBMITTED', label: 'Dépôt Dossier', icon: '📁' },
    { key: 'FIELD_SURVEY', label: 'Bornage / Géomètre', icon: '📍' },
    { key: 'PUBLIC_NOTICE', label: 'Publication Avis', icon: '📢' },
    { key: 'FINAL_REVIEW', label: 'Examen Final', icon: '⚖️' },
    { key: 'COMPLETED', label: 'Titre Signé', icon: '✍️' }
  ];

  constructor(private http: HttpClient) {}

  ngOnInit() {
    this.loadRequests();
  }

  loadRequests() {
    // In prototype, use mock if API fails
    this.http.get<any[]>('http://localhost:8081/api/titling/my-requests').subscribe({
      next: (data) => {
        this.requests = data;
        if (this.requests.length > 0) this.selectRequest(this.requests[0]);
        this.isLoading = false;
      },
      error: () => {
        this.requests = [
          {
            id: 'tit-1',
            type: 'FULL_TITLING',
            propertyLocation: 'Yaoundé, Soa',
            surfaceArea: 1200,
            currentStep: 'FIELD_SURVEY',
            status: 'IN_PROGRESS'
          }
        ];
        this.selectRequest(this.requests[0]);
        this.isLoading = false;
      }
    });
  }

  selectRequest(request: any) {
    this.selectedRequest = request;
    this.loadLogs(request.id);
  }

  loadLogs(requestId: string) {
    this.http.get<any[]>(`http://localhost:8081/api/titling/logs/${requestId}`).subscribe({
      next: (data) => this.logs = data,
      error: () => {
        this.logs = [
          { step: 'FIELD_SURVEY', adminComment: 'Le géomètre a effectué la descente. Bornage validé par les voisins.', createdAt: new Date() },
          { step: 'DOSSIER_SUBMITTED', adminComment: 'Dossier complet déposé. Numéro de suivi MINDCAF: 2024/YX/45', createdAt: new Date(Date.now() - 86400000 * 5) }
        ];
      }
    });
  }

  isStepCompleted(stepKey: string): boolean {
    const currentIdx = this.steps.findIndex(s => s.key === this.selectedRequest?.currentStep);
    const stepIdx = this.steps.findIndex(s => s.key === stepKey);
    return stepIdx <= currentIdx;
  }

  getProgressWidth(): string {
    const currentIdx = this.steps.findIndex(s => s.key === this.selectedRequest?.currentStep);
    const percent = currentIdx >= 0 ? (currentIdx / (this.steps.length - 1)) * 100 : 0;
    return percent + '%';
  }

  getStepLabel(stepKey: string): string {
    return this.steps.find(s => s.key === stepKey)?.label || stepKey;
  }
}
<div class="titling-tracker">
  <div class="header-section" style="margin-bottom: 2rem;">
    <h2>TITRER - Accélérateur Administratif</h2>
    <p>Suivez l'évolution de votre dossier de titrage au MINDCAF en temps réel.</p>
  </div>

  <div *ngIf="isLoading" style="text-align: center; padding: 2rem;">
    <p>Chargement de vos dossiers...</p>
  </div>

  <!-- Main Tracking View -->
  <div *ngIf="!isLoading && selectedRequest" class="tracker-card card">
    <div style="display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 2rem; border-bottom: 1px solid #eee; padding-bottom: 1rem;">
      <div>
        <h3 style="margin: 0; color: var(--mt-green);">{{ selectedRequest.propertyLocation }}</h3>
        <p style="margin: 5px 0 0 0; color: #666;">Type: {{ selectedRequest.type === 'FULL_TITLING' ? 'Titrage Complet' : 'Certificat de Propriété' }} | {{ selectedRequest.surfaceArea }} m²</p>
      </div>
      <div [style.background]="selectedRequest.status === 'IN_PROGRESS' ? 'var(--mt-gold)' : 'var(--mt-green)'" 
           style="color: white; padding: 5px 15px; border-radius: 20px; font-size: 0.8rem; font-weight: bold;">
        {{ selectedRequest.status }}
      </div>
    </div>

    <!-- Stepper UI -->
    <div class="stepper" style="display: flex; justify-content: space-between; position: relative; margin-bottom: 3rem;">
      <div class="stepper-line" style="position: absolute; top: 20px; left: 5%; width: 90%; height: 4px; background: #eee; z-index: 1;">
        <div class="stepper-line-active" [style.width]="getProgressWidth()"
             style="height: 100%; background: var(--mt-green); transition: width 0.5s ease-in-out;"></div>
      </div>

      <div *ngFor="let step of steps" class="step-item" style="z-index: 2; text-align: center; flex: 1;">
        <div class="step-circle" [style.background]="isStepCompleted(step.key) ? 'var(--mt-green)' : 'white'" 
             [style.border-color]="isStepCompleted(step.key) ? 'var(--mt-green)' : '#ddd'"
             style="width: 40px; height: 40px; border: 2px solid; border-radius: 50%; display: flex; align-items: center; justify-content: center; margin: 0 auto 10px; font-size: 1.2rem; transition: all 0.3s;">
          {{ isStepCompleted(step.key) ? '✅' : step.icon }}
        </div>
        <p style="font-size: 0.7rem; font-weight: bold; margin: 0; color: #444;">{{ step.label }}</p>
      </div>
    </div>

    <!-- Latest Update -->
    <div *ngIf="logs.length > 0" style="background: #f9f9f9; padding: 1rem; border-radius: 8px; border-left: 4px solid var(--mt-green);">
      <h4 style="margin: 0 0 5px 0; font-size: 0.9rem;">Dernière Mise à Jour ({{ getStepLabel(logs[0].step) }})</h4>
      <p style="margin: 0; font-size: 0.85rem; color: #555; line-height: 1.5;">{{ logs[0].adminComment }}</p>
      <p style="margin: 5px 0 0 0; font-size: 0.7rem; color: #999;">{{ logs[0].createdAt | date:'short' }}</p>
    </div>
  </div>

  <!-- Action CTAs -->
  <div style="margin-top: 2rem; display: grid; grid-template-columns: 1fr 1fr; gap: 1rem;">
    <button class="btn-primary" style="background-color: var(--mt-gold); color: var(--mt-black);">Nouvelle Demande</button>
    <button class="btn-primary" style="background-color: white; color: var(--mt-green); border: 1px solid var(--mt-green);">Contacter l'Agent</button>
  </div>

  <!-- History List -->
  <div *ngIf="logs.length > 1" style="margin-top: 3rem;">
    <h3>Historique du Dossier</h3>
    <div style="display: grid; gap: 10px;">
      <div *ngFor="let log of logs.slice(1)" class="card" style="padding: 1rem; font-size: 0.85rem;">
        <p style="margin: 0; font-weight: bold; color: var(--mt-green);">{{ getStepLabel(log.step) }}</p>
        <p style="margin: 5px 0 0 0; color: #666;">{{ log.adminComment }}</p>
        <p style="margin: 5px 0 0 0; font-size: 0.7rem; color: #bbb;">{{ log.createdAt | date:'short' }}</p>
      </div>
    </div>
  </div>
</div>
